class Solution(object):
    def isSubstringPresent(self, s):
        rev = s[::-1]
        subs = {s[i:i+2] for i in range(len(s) - 1)}
        rev_subs = {rev[i:i+2] for i in range(len(rev) - 1)}
        return bool(subs & rev_subs)
